#!/usr/bin/env bash
# Update the Homebrew tap with the node-bundled formula.
#
# The primary `ax-code` formula tracks GitHub release assets produced by the
# tag-driven release workflow. Run this script manually after the GitHub
# release assets are available.
#
# Inputs (env):
#   GITHUB_REF_NAME — release tag (e.g. v5.5.1)
#   GH_TOKEN        — read access to the ax-code release assets
#   TAP_TOKEN       — legacy write token for the Homebrew tap repo.
#   HOMEBREW_TAP_TOKEN — preferred write token for the Homebrew tap repo.
#                    Local manual runs may fall back to GH_TOKEN when it has
#                    tap write access.
set -euo pipefail

VERSION="${GITHUB_REF_NAME#v}"
TAG="v${VERSION}"
RELEASE_BASE="https://github.com/defai-digital/ax-code/releases/download/${TAG}"
SOURCE_REPO="${GITHUB_REPOSITORY:-defai-digital/ax-code}"
RELEASE_READ_TOKEN="${GH_TOKEN:-}"
LEGACY_TAP_AUTH_TOKEN="${TAP_TOKEN:-}"
NAMED_TAP_AUTH_TOKEN="${HOMEBREW_TAP_TOKEN:-}"
TAP_AUTH_LABELS=()
TAP_AUTH_TOKENS=()

add_tap_token() {
  local label="$1"
  local token="$2"
  local existing

  if [ -z "${token}" ]; then
    return
  fi

  if [ "${#TAP_AUTH_TOKENS[@]}" -gt 0 ]; then
    for existing in "${TAP_AUTH_TOKENS[@]}"; do
      if [ "${existing}" = "${token}" ]; then
        return
      fi
    done
  fi

  TAP_AUTH_LABELS+=("${label}")
  TAP_AUTH_TOKENS+=("${token}")
}

if [ -z "${RELEASE_READ_TOKEN}" ]; then
  echo "::error::GH_TOKEN is required to read release assets from ${SOURCE_REPO}"
  exit 1
fi

# Prefer the legacy TAP_TOKEN first so existing tap-write credentials keep
# working even if the newer HOMEBREW_TAP_TOKEN secret is present but scoped
# incorrectly.
add_tap_token "TAP_TOKEN" "${LEGACY_TAP_AUTH_TOKEN}"
add_tap_token "HOMEBREW_TAP_TOKEN" "${NAMED_TAP_AUTH_TOKEN}"

if [ "${#TAP_AUTH_TOKENS[@]}" -eq 0 ]; then
  if [ "${GITHUB_ACTIONS:-}" = "true" ]; then
    echo "::error::HOMEBREW_TAP_TOKEN is not configured; stable releases must update the Homebrew tap"
    exit 1
  fi
  add_tap_token "GH_TOKEN" "${GH_TOKEN:-}"
fi
if [ "${#TAP_AUTH_TOKENS[@]}" -eq 0 ]; then
  echo "::error::TAP_TOKEN, HOMEBREW_TAP_TOKEN, or a tap-write GH_TOKEN is required to update the Homebrew tap"
  exit 1
fi
# Keep release downloads on the source-repo token. The tap write token may be
# scoped only to defai-digital/homebrew-ax-code and can fail release reads with
# "Resource not accessible by personal access token".
export GH_TOKEN="${RELEASE_READ_TOKEN}"

sha256_file() {
  if command -v sha256sum >/dev/null 2>&1; then
    sha256sum "$1" | cut -d' ' -f1
  else
    shasum -a 256 "$1" | cut -d' ' -f1
  fi
}

download_asset() {
  local asset="$1"
  local dest="/tmp/${asset}"
  local attempts=0
  local max_attempts=30

  rm -f "${dest}"
  while ! gh release download "${TAG}" \
    --repo "${SOURCE_REPO}" \
    --pattern "${asset}" \
    --dir /tmp \
    --clobber; do
    attempts=$((attempts + 1))
    echo "::warning::Attempt ${attempts}/${max_attempts} failed for ${asset}; retrying in 5 seconds"
    if [ "$attempts" -ge "$max_attempts" ]; then
      echo "::error::release asset ${asset} not available from ${SOURCE_REPO}@${TAG} after ${max_attempts} attempts"
      exit 1
    fi
    sleep 5
  done
  if [ ! -f "${dest}" ]; then
    echo "::error::release asset download succeeded but ${dest} was not created"
    exit 1
  fi

  sha256_file "${dest}"
}

DARWIN_ARM64_ASSET="ax-code-darwin-arm64.zip"

DARWIN_ARM64_SHA="$(download_asset "${DARWIN_ARM64_ASSET}")"

cat > /tmp/ax-code.rb << HEADER
# typed: false
# frozen_string_literal: true

# Auto-generated by ax-code release tooling — do not edit manually.
#
# node-bundled formula for ax-code. The macOS asset is a node-bundled
# distribution (bin + lib + node_modules), not a single compiled binary, so the
# whole tree installs into libexec and bin/ax-code is a wrapper that runs the
# bundle with the Homebrew node (the launcher needs --experimental-ffi for
# OpenTUI's node:ffi backend).
class AxCode < Formula
  desc "Sovereign AI coding agent — provider-agnostic, LSP-first"
  homepage "https://github.com/defai-digital/ax-code"
  version "${VERSION}"
  license "MIT"

  on_macos do
    depends_on arch: :arm64
    url "${RELEASE_BASE}/${DARWIN_ARM64_ASSET}"
    sha256 "${DARWIN_ARM64_SHA}"
  end

  depends_on "node"
  depends_on "ripgrep"

  def install
    libexec.install Dir["*"]
    (bin/"ax-code").write <<~SH
      #!/bin/sh
      exec "#{Formula["node"].opt_bin}/node" --experimental-ffi "#{libexec}/lib/index-node-tui.js" "\$@"
    SH
    chmod 0755, bin/"ax-code"
  end

  test do
    assert_match version.to_s, shell_output("#{bin}/ax-code --version")
  end
end
HEADER

echo "Generated formula:"
cat /tmp/ax-code.rb

try_update_tap() {
  local label="$1"
  local token="$2"
  local tap_dir
  local status

  tap_dir="$(mktemp -d)"
  echo "Updating Homebrew tap with ${label}"

  # Switch to the tap write token only after all source-repo release assets have
  # been downloaded and hashed.
  export GH_TOKEN="${token}"
  gh auth setup-git || {
    status=$?
    rm -rf "${tap_dir}"
    return "${status}"
  }
  gh repo clone defai-digital/homebrew-ax-code "${tap_dir}" -- --depth 1 || {
    status=$?
    rm -rf "${tap_dir}"
    return "${status}"
  }
  cp /tmp/ax-code.rb "${tap_dir}/ax-code.rb" || {
    status=$?
    rm -rf "${tap_dir}"
    return "${status}"
  }
  (
    cd "${tap_dir}" || exit
    git config user.name "github-actions[bot]" || exit
    git config user.email "github-actions[bot]@users.noreply.github.com" || exit
    git add ax-code.rb || exit
    if git diff --cached --quiet; then
      echo "Formula unchanged, skipping push"
    else
      git commit -m "Update ax-code to v${VERSION}" || exit
      git push || exit
      echo "Homebrew tap updated to v${VERSION}"
    fi
  )
  status=$?
  rm -rf "${tap_dir}"
  return "${status}"
}

last_index=$((${#TAP_AUTH_TOKENS[@]} - 1))
for index in "${!TAP_AUTH_TOKENS[@]}"; do
  if try_update_tap "${TAP_AUTH_LABELS[$index]}" "${TAP_AUTH_TOKENS[$index]}"; then
    exit 0
  fi

  if [ "${index}" -lt "${last_index}" ]; then
    echo "::warning::Homebrew tap update failed with ${TAP_AUTH_LABELS[$index]}; trying next configured token"
  fi
done

echo "::error::All configured Homebrew tap tokens failed to update defai-digital/homebrew-ax-code"
exit 1
